PRAGMA defer_foreign_keys=TRUE;
CREATE TABLE users (   id INTEGER PRIMARY KEY AUTOINCREMENT,   telegram_id INTEGER NOT NULL UNIQUE,   username TEXT,   first_name TEXT,   phone TEXT,   created_at TEXT DEFAULT CURRENT_TIMESTAMP,   updated_at TEXT DEFAULT CURRENT_TIMESTAMP );
CREATE TABLE services (    id INTEGER PRIMARY KEY AUTOINCREMENT,    code TEXT NOT NULL UNIQUE,    name TEXT NOT NULL,    duration_minutes INTEGER NOT NULL DEFAULT 60,    active INTEGER NOT NULL DEFAULT 1,    sort_order INTEGER NOT NULL DEFAULT 0 );
CREATE TABLE cities (    id INTEGER PRIMARY KEY AUTOINCREMENT,    code TEXT NOT NULL UNIQUE,    name TEXT NOT NULL,    calendar_id TEXT,    active INTEGER NOT NULL DEFAULT 1 );
CREATE TABLE bookings (    id TEXT PRIMARY KEY,    user_id INTEGER NOT NULL,    service_id INTEGER NOT NULL,    city_id INTEGER NOT NULL,    booking_date TEXT NOT NULL,    start_time TEXT NOT NULL,    end_time TEXT NOT NULL,    status TEXT NOT NULL DEFAULT 'confirmed',    calendar_event_id TEXT,    created_at TEXT DEFAULT CURRENT_TIMESTAMP,    updated_at TEXT DEFAULT CURRENT_TIMESTAMP , reminder_sent INTEGER NOT NULL DEFAULT 0);
CREATE TABLE closed_dates (    id INTEGER PRIMARY KEY AUTOINCREMENT,    city_id INTEGER NOT NULL,    date TEXT NOT NULL,    reason TEXT,    created_at TEXT DEFAULT CURRENT_TIMESTAMP,    UNIQUE(city_id, date) );
CREATE TABLE reminders (    id INTEGER PRIMARY KEY AUTOINCREMENT,    booking_id TEXT NOT NULL,    type TEXT NOT NULL,    send_at TEXT NOT NULL,    sent INTEGER DEFAULT 0,    sent_at TEXT );
CREATE TABLE booking_logs (    id INTEGER PRIMARY KEY AUTOINCREMENT,    booking_id TEXT NOT NULL,    action TEXT NOT NULL,    details TEXT,    created_at TEXT DEFAULT CURRENT_TIMESTAMP );
DELETE FROM sqlite_sequence;
